+// ============================================================================
+// Current Context (thread-local)
+// ============================================================================
+
+/// Thread-local current context
+threadlocal var current_context: ?*Context = null;
+
+/// Get the current context (creates one if none exists)
+pub fn copyContext() ?*Context {
+    return current_context;
+}
+
